// frontend/src/pages/Refund.jsx — Member 4
// Automatic Refund Page

import { useState, useEffect } from "react";
import { getCrowdfundingContract, fromWei, isDeadlinePassed } from "../utils/contracts";

export default function Refund({ user }) {
  const [refundable, setRefundable] = useState([]);
  const [loading, setLoading] = useState(false);
  const [claiming, setClaiming] = useState(null); // campaignId being claimed
  const [error, setError] = useState("");
  const [statusMap, setStatusMap] = useState({});

  useEffect(() => {
    loadRefundableCampaigns();
  }, [user]);

  async function loadRefundableCampaigns() {
    try {
      setLoading(true);
      setError("");
      const contract = await getCrowdfundingContract();
      const all = await contract.getAllCampaigns();

      // Filter: ended + goal NOT met + user contributed
      const results = await Promise.all(
        all.map(async (c) => {
          const ended = isDeadlinePassed(c.deadline);
          const goalMissed = Number(fromWei(c.amountRaised)) < Number(fromWei(c.goal));
          const myAmount = await contract.getContribution(c.id, user.address);
          
          return {
            ...c,
            myContribution: fromWei(myAmount),
            eligible: ended && goalMissed && Number(fromWei(myAmount)) > 0,
          };
        })
      );

      setRefundable(results.filter((c) => c.eligible));
    } catch (err) {
      console.error(err);
      setError("Failed to load campaigns: " + err.message);
    } finally {
      setLoading(false);
    }
  }

  async function claimRefund(campaignId) {
    try {
      setClaiming(campaignId);
      setStatusMap({ ...statusMap, [campaignId]: "Processing transaction..." });
      
      const contract = await getCrowdfundingContract();
      const tx = await contract.claimRefund(campaignId);
      
      setStatusMap({ ...statusMap, [campaignId]: "Waiting for confirmation..." });
      await tx.wait();
      
      setStatusMap({ ...statusMap, [campaignId]: "Refund successful!" });
      
      // Reload the list after 2 seconds to remove the refunded campaign
      setTimeout(() => {
        loadRefundableCampaigns();
      }, 2000);

    } catch (err) {
      console.error(err);
      const errorMsg = err.reason || err.message || "Transaction failed";
      setStatusMap({ ...statusMap, [campaignId]: `Error: ${errorMsg}` });
    } finally {
      setClaiming(null);
    }
  }

  return (
    <div>
      <h2 style={headerStyle}>Eligible Refunds</h2>
      <p style={subHeaderStyle}>
        Claim back your ETH from campaigns that missed their funding goals.
      </p>

      {error && <div style={errorBanner}>{error}</div>}

      {loading ? (
        <div style={{ textAlign: "center", padding: "40px 0" }}>
          <div style={spinnerStyle} />
          <p style={{ color: "#666", marginTop: 12 }}>Checking eligibility...</p>
        </div>
      ) : refundable.length === 0 ? (
        <div style={emptyStateStyle}>
          <div style={emptyIconStyle}>🎉</div>
          <h3 style={{ margin: "0 0 8px", color: "#333" }}>No refunds pending</h3>
          <p style={{ margin: 0, color: "#666", fontSize: 14 }}>
            You don't have any active contributions in failed campaigns.
          </p>
        </div>
      ) : (
        <div style={gridStyle}>
          {refundable.map((c, i) => (
            <div key={i} style={cardStyle}>
              <div style={cardHeaderStyle}>
                <h4 style={cardTitleStyle}>{c.title}</h4>
                <span style={badgeStyle}>Failed</span>
              </div>
              
              <div style={cardBodyStyle}>
                <p style={statStyle}>
                  Goal: <strong>{fromWei(c.goal)} ETH</strong>
                </p>
                <p style={statStyle}>
                  Raised: <strong>{fromWei(c.amountRaised)} ETH</strong>
                </p>
                <p style={highlightStyle}>
                  Your Contribution: <span>{c.myContribution} ETH</span>
                </p>
              </div>

              <div style={actionRowStyle}>
                <button
                  onClick={() => claimRefund(c.id)}
                  disabled={claiming === c.id}
                  style={claiming === c.id ? disabledBtnStyle : btnStyle}
                >
                  {claiming === c.id ? "Processing..." : "Claim Refund"}
                </button>
              </div>

              {statusMap[c.id] && (
                <div style={{
                  marginTop: 12,
                  fontSize: 13,
                  fontWeight: 500,
                  color: statusMap[c.id].includes("Error") ? "#D85A30" : "#1D9E75"
                }}>
                  {statusMap[c.id]}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
      
      {/* Required for spinner animation */}
      <style>
        {`@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }`}
      </style>
    </div>
  );
}

// ─── Styles matching your team's design ────────────────────────

const headerStyle = {
  fontSize: 24,
  fontWeight: "bold",
  margin: "0 0 8px",
  color: "#333"
};

const subHeaderStyle = {
  fontSize: 15,
  color: "#666",
  margin: "0 0 24px",
  lineHeight: "1.5"
};

const gridStyle = {
  display: "grid",
  gridTemplateColumns: "repeat(auto-fill, minmax(320px, 1fr))",
  gap: 20
};

const cardStyle = {
  background: "#fff",
  border: "1px solid #E5E9F0",
  borderTop: "6px solid #D85A30", // Using the Red/Orange accent for refunds
  borderRadius: 16,
  padding: 20,
  display: "flex",
  flexDirection: "column",
  boxShadow: "0 2px 8px rgba(0,0,0,0.02)"
};

const cardHeaderStyle = {
  display: "flex",
  justifyContent: "space-between",
  alignItems: "flex-start",
  marginBottom: 16
};

const cardTitleStyle = {
  margin: 0,
  fontSize: 18,
  fontWeight: "600",
  color: "#333",
  flex: 1,
  paddingRight: 12
};

const badgeStyle = {
  background: "#FCE8E3",
  color: "#D85A30",
  padding: "4px 10px",
  borderRadius: 20,
  fontSize: 12,
  fontWeight: "bold"
};

const cardBodyStyle = {
  marginBottom: 20,
  flex: 1
};

const statStyle = {
  margin: "0 0 6px",
  fontSize: 14,
  color: "#555"
};

const highlightStyle = {
  margin: "12px 0 0",
  padding: "10px",
  background: "#f8f8fc",
  borderRadius: 8,
  fontSize: 14,
  fontWeight: "600",
  color: "#333",
  display: "flex",
  justifyContent: "space-between"
};

const actionRowStyle = {
  marginTop: "auto"
};

const btnStyle = {
  width: "100%",
  padding: "12px",
  background: "#D85A30",
  color: "#fff",
  border: "none",
  borderRadius: 10,
  fontSize: 15,
  fontWeight: "bold",
  cursor: "pointer",
  transition: "0.2s ease"
};

const disabledBtnStyle = {
  ...btnStyle,
  background: "#E5E9F0",
  color: "#999",
  cursor: "not-allowed"
};

const errorBanner = {
  background: "#FCE8E3",
  color: "#D85A30",
  padding: "12px 16px",
  borderRadius: 10,
  marginBottom: 24,
  fontSize: 14,
  fontWeight: 500
};

const emptyStateStyle = {
  textAlign: "center",
  padding: "60px 20px",
  background: "#fff",
  border: "1px dashed #ccc",
  borderRadius: 16
};

const emptyIconStyle = {
  fontSize: 48,
  marginBottom: 16
};

const spinnerStyle = {
  width: 36,
  height: 36,
  border: "3px solid #f0f0f0",
  borderTop: "3px solid #7F77DD",
  borderRadius: "50%",
  animation: "spin 0.8s linear infinite",
  margin: "0 auto"
};
